const resp = $input.first() ? ($input.first().json || {}) : {};
let txt = '';
try {
  if (resp.candidates && resp.candidates[0] && resp.candidates[0].content && resp.candidates[0].content.parts && resp.candidates[0].content.parts[0]) {
    txt = resp.candidates[0].content.parts[0].text || '';
  }
} catch (e) { txt = ''; }

const consulta = $('Normalizar consulta').item.json;
let urgencia = 'Media';
let tipo_servicio = consulta.servicio || 'No especificado';
let resumen = '';
let sugerencia_respuesta = '';

if (txt) {
  try {
    const p = JSON.parse(txt);
    if (p.urgencia) urgencia = p.urgencia;
    if (p.tipo_servicio) tipo_servicio = p.tipo_servicio;
    if (p.resumen) resumen = p.resumen;
    if (p.sugerencia_respuesta) sugerencia_respuesta = p.sugerencia_respuesta;
  } catch (e) {}
}

if (!resumen) {
  resumen = 'No se pudo generar el resumen automatico con IA. Por favor revisar la consulta del cliente manualmente.';
}
if (!sugerencia_respuesta) {
  sugerencia_respuesta = 'Contactar al cliente, agradecer la consulta y pedir mas detalles sobre fechas exactas, cantidad de pasajeros y presupuesto estimado.';
}

return [{ json: { urgencia, tipo_servicio, resumen, sugerencia_respuesta, generado_por: 'Gemini 2.5 Flash' } }];

const consulta = $('Normalizar consulta').item.json;
const email = (consulta.email || '').toString().trim().toLowerCase();
const filas = $input.all().map(i => i.json);
const propias = filas.filter(f => (f.email || '').toString().trim().toLowerCase() === email);
const fila = propias.length ? propias[propias.length - 1] : null;
const estado = fila ? (fila.estado || '').toString().trim() : 'NO_ENCONTRADA';
return [{ json: { estado, encontrada: !!fila, total_filas: filas.length } }];

